import{_ as i,o as e,c as n,ak as l}from"./chunks/framework.571fwNe4.js";const c=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"技术/AUTOSAR 实践/MCAL 模块详解/Dio.md","filePath":"技术/AUTOSAR 实践/MCAL 模块详解/Dio.md"}'),t={name:"技术/AUTOSAR 实践/MCAL 模块详解/Dio.md"};function a(r,o,D,p,d,_){return e(),n("div",null,[...o[0]||(o[0]=[l('<p>Dio 模块提供了对于以下硬件的读写服务：</p><ul><li>DIO 通道（端口）</li><li>DIO端口</li><li>DIO 通道组</li></ul><p>Dio 模块只对于在 PORT 中完成适当设置的端口起作用。因此，对于 Port 部分的初始化设置并不在 Dio 模块中。详细说明见 <a href="./Port.html">Port</a>。</p><p>被 Dio 驱动配置的硬件是 GPIO。通道到引脚的映射可以通过查看 IO Muxing documention 得出。</p><p>实际通道的值可以通过以下公式得出：</p><blockquote><p>Channel = DioChannelId + DioPortId*32</p></blockquote><p>其中，DioPortId 是每个 Dio Port 口的数字标识，即对 PortA/B/C/D/E 映射为0/1/2/3/4，而DioChannelId 即每个端口的各个通道 Id，如：</p><p>对于通道 GPIO[35]，可以在 Reference Manual 中找到是 PTB3。其 DioChannelId = 3，DioPortId = 1。</p><p>对于 Dio 的配置方式和 API 使用，UM/Driver usage and configuration tips 中给出以下描述：</p><p>Dio驱动的 API 以通道、端口和通道组为单位工作。</p><p>对于 Dio 通道：</p><p>可以对于指定引脚使用 Dio_ReadChannel(), Dio_WriteChannel(), Dio_FlipChannel() 函数操作。但是在此之前，需要进行以下操作（以 PE[5] 为例）：</p><ol><li>根据上述说明，DioPortId = 4, DioChannelId = 5。</li><li>在 DioPort 中新建一个新的 Port，将其 Id 改为 4。</li><li>进入该 Port 中，新建一个 DioChannel，进行命名，并将其 DioChannelId 改为 13。</li><li>进入 <code>Generate/include/Dio_Cfg.h</code>，在 DEFINES AND MACROS 中寻找到上述设定的命名，并找到其标识符对应的宏定义。如：<code>DioConf_DioChannel_DioChannel_0</code>。</li><li>利用上述 API 进行操作。</li></ol><p>同样的，AUTOSAR 还规定了可以对于一组 Port 进行操作的 API：</p><ul><li>Dio_ReadPort()</li><li>Dio_WritePort()</li><li>Dio_MaskedWritePort()</li></ul><p>用法与对于 Channel 的相似。</p><p>关于单个函数的定义与使用方式可以参考 UM/Module Documentation/Function Reference（6.1.3.x)。</p><p>对于 Dio 的各项配置说明由于理解难度不大，在此不再赘述，详情请参考 User Manual。</p>',18)])])}const I=i(t,[["render",a]]);export{c as __pageData,I as default};
